// ============================================================
// FILTER VICTIMS BY SECTOR + REDACT NAMES
// ============================================================
// Only keep victims in sectors we care about for our org.
// Customize this list to match your industry or client base.
//
// IMPORTANT: Victim names are REDACTED and replaced with
// fabricated company names for webinar/recording safety.
// Real victim data from ransomware.live should never be
// displayed in public presentations.
// ============================================================

const targetSectors = [
  'manufacturing',
  'healthcare',
  'finance',
  'technology',
  'energy',
  'government'
];

// Fabricated company names for redaction (rotate through these)
const FAKE_COMPANIES = [
  'Apex Industrial Solutions', 'Meridian Health Partners',
  'Cobalt Financial Group', 'Zenith Technologies Inc',
  'Pinnacle Energy Corp', 'Vanguard Public Services',
  'Atlas Manufacturing Ltd', 'Horizon Medical Systems',
  'Sterling Capital Advisors', 'Quantum Dynamics Corp',
  'Ironbridge Logistics', 'Cascade Healthcare Network',
  'Summit Engineering Group', 'Pacific Rim Trading Co',
  'Northwind Aerospace', 'Redwood Pharmaceuticals'
];
let fakeIndex = 0;

function redactVictimName() {
  const name = FAKE_COMPANIES[fakeIndex % FAKE_COMPANIES.length];
  fakeIndex++;
  return name;
}

const victims = $input.all();
const results = [];

for (const item of victims) {
  const victim = item.json;

  // ransomware.live uses 'activity' field for sector info
  const sector = (victim.activity || victim.sector || '').toLowerCase();

  const matchesSector = targetSectors.some(s => sector.includes(s));

  if (matchesSector) {
    results.push({
      json: {
        victim_name: redactVictimName(),
        group_name: victim.group_name || victim.group || 'Unknown',
        sector: victim.activity || victim.sector || 'Unknown',
        discovered: victim.discovered || victim.date || 'Unknown',
        country: victim.country || 'Unknown',
        website: '[REDACTED]'
      }
    });
  }
}

if (results.length === 0) {
  return [{ json: { message: 'No victims found in target sectors', count: 0 } }];
}

return results;

// ============================================================
// EXTRACT UNIQUE THREAT GROUPS
// ============================================================
// Deduplicate the ransomware groups targeting our sectors
// so we fetch each group profile only once.
// ============================================================

const items = $input.all();

// Handle 'no victims' case
if (items.length === 1 && items[0].json.count === 0) {
  return [{ json: { no_results: true, message: items[0].json.message } }];
}

const groupSet = new Set();
const victimsByGroup = {};

for (const item of items) {
  const group = item.json.group_name;
  if (group && group !== 'Unknown') {
    groupSet.add(group);
    if (!victimsByGroup[group]) {
      victimsByGroup[group] = [];
    }
    victimsByGroup[group].push(item.json);
  }
}

const groups = Array.from(groupSet).map(g => ({
  json: {
    group_name: g,
    victim_count: victimsByGroup[g].length,
    victims: victimsByGroup[g]
  }
}));

return groups.length > 0 ? groups : [{ json: { no_results: true, message: 'No groups identified' } }];

// ============================================================
// FORMAT THREAT SUMMARY
// ============================================================
// Build a Markdown-formatted threat brief suitable for
// Slack, email, or a wiki page.
// ============================================================

const items = $input.all();
const now = new Date().toISOString().split('T')[0];

let markdown = `# 🔒 Ransomware Threat Monitor\n`;
markdown += `**Generated:** ${now}\n\n`;
markdown += `---\n\n`;

for (const item of items) {
  const profile = item.json;
  const groupName = (profile.name || profile.group_name || 'Unknown').toUpperCase();

  markdown += `## ${groupName}\n\n`;

  if (profile.description) {
    markdown += `${profile.description.substring(0, 300)}...\n\n`;
  }

  if (profile.locations) {
    markdown += `**Suspected Location:** ${profile.locations}\n`;
  }

  if (profile.profile) {
    const p = Array.isArray(profile.profile) ? profile.profile : [profile.profile];
    for (const entry of p) {
      if (entry && typeof entry === 'string') {
        markdown += `${entry.substring(0, 200)}\n`;
      }
    }
    markdown += `\n`;
  }

  markdown += `---\n\n`;
}

markdown += `\n_Monitor powered by ransomware.live API + n8n_\n`;
markdown += `_SANS Webinar Demo — AI-Powered Ransomware Intelligence_`;

return [{
  json: {
    summary: markdown,
    group_count: items.length,
    generated_at: now
  }
}];

// No groups found in monitored sectors — log it
return [{
  json: {
    status: 'clear',
    message: 'No ransomware activity detected in monitored sectors this cycle.',
    timestamp: new Date().toISOString()
  }
}];
